def solution():
    total = 0
    # Start from 2, as 1 is excluded. Upper bound of 1,000,000 is sufficient.
    for i in range(2, 1000000):
        # Sum of the fifth powers of each digit
        digit_power_sum = sum(int(d)**5 for d in str(i))
        if i == digit_power_sum:
            total += i
    return total


if __name__ == "__main__":
    print(solution())
